const items = $input.all();
const results = [];
const now = new Date();
const DEBOUNCE_SECONDS = 300; // 5 mins for email

for (const item of items) {
  const data = item.json;
  if (!data.pending_reply) continue;

  // If last_reply_at is null, this is a brand-new thread — respond immediately
  if (!data.last_reply_at) {
    results.push({ json: data });
    continue;
  }

  const pendingSince = new Date(data.last_reply_at);
  const ageSeconds = (now.getTime() - pendingSince.getTime()) / 1000;

  if (ageSeconds >= DEBOUNCE_SECONDS) {
    results.push({ json: data });
  }
}
return results;

const thread = $('Filter — Ready Email Threads').first().json;
const history = $('Get Email Message History').all().map(i => i.json).reverse();

const historyStr = history.map((m, i) => `[${i + 1}] Direction: ${m.direction} | Content: ${m.content}`).join('\n\n---');

const userMessage = `COLLECTED DATA:
Address: ${thread.collected_address ?? 'NOT YET COLLECTED'}
Wishes: ${thread.collected_wishes ?? 'NOT YET COLLECTED'}
Dimensions: ${thread.collected_dimensions ?? 'NOT YET COLLECTED'}
Phone: ${thread.collected_phone ?? 'NOT YET COLLECTED'}
Current step: ${thread.qualification_step ?? 1}
Qualification complete: ${thread.qualification_complete ? 'YES' : 'NO'}

EMAIL MESSAGE HISTORY:
${historyStr || '(No prior messages)'}`;

return [{ json: { userMessage, thread_id: thread.id, gmail_thread_id: thread.gmail_thread_id, classification: thread.classification, qualification_step: thread.qualification_step } }];

// Parse & Validate Anthropic AI Response
const convData = $node['Build AI Prompt (Email)'].json;
let aiOutput;

try {
  let rawContent = $input.first().json.content?.[0]?.text || '';

  if (typeof rawContent === 'string') {
    rawContent = rawContent.replace(/```json\n?|\n?```/g, '').trim();
  }

  if (typeof rawContent === 'object' && rawContent !== null) {
    aiOutput = rawContent;
  } else {
    aiOutput = JSON.parse(rawContent);
  }

  if (!aiOutput.messages || !Array.isArray(aiOutput.messages) || aiOutput.messages.length === 0) {
    throw new Error('Missing or empty messages array');
  }
  if (typeof aiOutput.currentStep === 'undefined') {
    aiOutput.currentStep = convData.qualification_step || 1;
  }
  if (typeof aiOutput.qualificationComplete === 'undefined') {
    aiOutput.qualificationComplete = false;
  }
  if (!aiOutput.extracted) {
    aiOutput.extracted = {};
  }

} catch (e) {
  aiOutput = {
    messages: ['Er is een fout opgetreden. Probeer het opnieuw.'],
    extracted: {},
    currentStep: convData.qualification_step || 1,
    qualificationComplete: false,
    respond: true
  };
}

return [{
  json: {
    ai_messages:            aiOutput.messages,
    ai_reply:               aiOutput.messages[0],
    respond:                aiOutput.respond ?? true,

    extracted_address:      aiOutput.extracted.address    || null,
    extracted_wishes:       aiOutput.extracted.wishes     || null,
    extracted_dimensions:   aiOutput.extracted.dimensions || null,
    extracted_phone:        aiOutput.extracted.phone      || null,
    extracted_email:        aiOutput.extracted.email      || null,

    currentStep:            aiOutput.currentStep,
    qualificationComplete:  aiOutput.qualificationComplete,

    thread_id:              convData.thread_id,
    gmail_thread_id:        convData.gmail_thread_id,
    collected_address:      aiOutput.extracted.address    || null,
    collected_wishes:       aiOutput.extracted.wishes     || null,
    collected_dimensions:   aiOutput.extracted.dimensions || null,
    collected_phone:        aiOutput.extracted.phone      || null,
    collected_email:        aiOutput.extracted.email      || null
  }
}];

for (const item of $input.all()) {
  const rawText = item.json.content[0].text;

  // Strip markdown code fences (```json ... ```)
  const cleaned = rawText.replace(/```json\n?|\n?```/g, "").trim();

  // Parse the JSON string
  const parsed = JSON.parse(cleaned);

  // Extract the respond status
  item.json.respond = parsed.respond;

  // Optional: extract other fields too
  item.json.messages        = parsed.messages;
  item.json.currentStep     = parsed.currentStep;
  item.json.qualificationComplete = parsed.qualificationComplete;
  item.json.extracted       = parsed.extracted;
}

return $input.all();
